"use client";

const safeUserData = userData ?? {
  personalInfo: { emergencyContacts: [] },
  currentMedical: {
    doctors: [],
    medications: [],
    conditions: []
  }
};

import { useState } from 'react';
import {
  Calendar, Users, Stethoscope, Pill, Activity, AlertCircle, Sparkles, X, Phone, Clock,
  ChevronRight, FileText, Edit, Trash2, ChevronLeft, Menu
} from 'lucide-react';

type Appointment = {
  id: string;
  date: string;
  time: string;
  title: string;
  type?: string;
};

type UserData = {
  personalInfo: { emergencyContacts: { name: string; phone: string; relation: string }[] };
  currentMedical: { 
    doctors: { name: string; phone: string; speciality: string }[];
    medications: { name: string; dosage: string; frequency: string }[];
    conditions?: string[];
  };
};

const formatDateKey = (d: Date) => 
  `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;

type Props = {
  userData: UserData;
  onNavigateToVault: () => void;
  onNavigateToProfile: () => void;
  appointments: Appointment[];
  onAddAppointment: (appointment: Appointment) => void;
  onDeleteAppointment: (id: string) => void;
  onUpdateEmergencyContacts: (contacts: any[]) => void;
};

export default function HomePage({
  userData,
  onNavigateToVault,
  onNavigateToProfile,
  appointments = [], // Add the = [] here
  onAddAppointment,
// ...
  onDeleteAppointment,
  onUpdateEmergencyContacts
}: Props) {
  const [activeModal, setActiveModal] = useState<string | null>(null);
  const [showSummaryModal, setShowSummaryModal] = useState(false);
  const [summaryText, setSummaryText] = useState('');
  const [recentDocs, setRecentDocs] = useState<any[]>([]);
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // ADD THESE LINES HERE:
  const emergencyContacts = userData?.personalInfo?.emergencyContacts || [];
  const doctors = userData?.currentMedical?.doctors || [];
  const medications = userData?.currentMedical?.medications || [];
  const conditions = userData?.currentMedical?.conditions || [];

  const handleGetSummary = () => {
    const demoDocs = [
      { id: '101', name: 'Blood Test Report.pdf' },
      { id: '102', name: 'X-Ray Results.pdf' },
      { id: '103', name: 'Prescription.pdf' },
    ];
    setRecentDocs(demoDocs);
    const summary = summaryText ? 
      `📊 PROGRESSIVE ANALYSIS\n\nComparing with previous baselines shows positive trends.\n\nRECOMMENDATION:\n• Continue medication\n• Follow-up in 3 months` :
      `📋 BASELINE SUMMARY\n\nEstablishing baseline for future comparisons.\n\nKEY FINDINGS:\n• Blood levels normal\n• No critical allergies\n• No interaction risks`;
    setSummaryText(summary);
    setShowSummaryModal(true);
  };

  const cards = [
    { id: 'appointments', title: 'Upcoming Appointments', icon: Calendar, color: '#00838B' },
    { id: 'emergency', title: 'Emergency Contacts', icon: Users, color: '#006770' },
    { id: 'doctors', title: 'Medical Team', icon: Stethoscope, color: '#00838B' },
    { id: 'medications', title: 'Current Medication', icon: Pill, color: '#006770' },
  ];

  const renderModal = () => {
    switch(activeModal) {
      case 'appointments':
        return <CalendarView appointments={appointments} onAddAppointment={onAddAppointment} onDeleteAppointment={onDeleteAppointment} />;
      case 'emergency':
        return <EmergencyView data={emergencyContacts} onDelete={(i: number) => onUpdateEmergencyContacts(emergencyContacts.filter((_, idx) => idx !== i))} />;
      case 'doctors':
        return <DoctorsView data={doctors} />;
      case 'medications':
        return <MedsView data={medications} />;
      default: return null;
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-b from-[#003B46] via-[#006770] via-[#00838B] to-[#00A3A9] pb-10 font-sans">
      
      <header className="sticky top-0 z-40 border-b border-white/20 shadow-sm" style={{ background: 'linear-gradient(90deg, #006770 0%, #00838B 40%, #00A3A9 100%)' }}>
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 sm:w-12 sm:h-12 bg-white rounded-full flex items-center justify-center shadow-md p-2">
                <div className="w-full h-full bg-teal-600 rounded-full"></div>
              </div>
              <h1 className="hidden sm:block text-xl font-bold text-white tracking-wide">Vytara</h1>
            </div>

            <div className="flex items-center gap-3">
              <button onClick={handleGetSummary} className="flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg bg-purple-600 text-white hover:bg-purple-700 transition-all shadow-lg font-semibold text-xs sm:text-sm border border-purple-400/30">
                <Sparkles className="w-4 h-4" />
                <span>Get Summary</span>
              </button>

              <div className="relative">
                <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="p-2 text-white hover:bg-white/20 rounded-lg flex items-center justify-center transition border border-white/30 bg-white/10 backdrop-blur-sm">
                  {isMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
                </button>
                {isMenuOpen && (
                  <div className="absolute right-0 mt-2 w-56 bg-white rounded-xl shadow-xl border border-gray-100 z-50 overflow-hidden">
                    <button onClick={() => { onNavigateToVault(); setIsMenuOpen(false); }} className="w-full text-left px-4 py-3 text-sm font-medium text-gray-700 hover:bg-teal-50 hover:text-[#006770] transition">Vault</button>
                    <button onClick={() => { onNavigateToProfile(); setIsMenuOpen(false); }} className="w-full text-left px-4 py-3 text-sm font-medium text-gray-700 hover:bg-teal-50 hover:text-[#006770] transition">Profile</button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        
        <div className="flex justify-center mb-12">
          <button onClick={() => alert('🚨 SOS Alert! Emergency contacts notified.')} className="group relative w-32 h-32 sm:w-40 sm:h-40 bg-gradient-to-br from-red-500 to-red-700 text-white rounded-full shadow-2xl flex flex-col items-center justify-center hover:scale-110 transition-transform duration-200">
            <div className="absolute inset-0 rounded-full bg-red-400/20 blur-xl group-hover:bg-red-400/40 transition"></div>
            <AlertCircle className="w-10 h-10 sm:w-14 sm:h-14 mb-1 relative z-10" />
            <span className="text-lg sm:text-2xl font-bold relative z-10">SOS</span>
          </button>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 sm:gap-6 mb-8">
          {cards.map((card) => {
            const Icon = card.icon;
            return (
              <div key={card.id} className="cursor-pointer transition-all duration-300 hover:scale-105 group" onClick={() => setActiveModal(card.id)}>
                <div className="bg-white rounded-3xl shadow-xl shadow-teal-900/20 p-6 border border-white/20 hover:shadow-2xl hover:shadow-teal-900/30 transition-all h-full flex flex-col items-center justify-center relative overflow-hidden">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-orange-50 to-teal-50 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2 opacity-60 pointer-events-none"></div>
                  <div className="w-16 h-16 rounded-full flex items-center justify-center mb-4 relative z-10 transition-all group-hover:scale-110" style={{ backgroundColor: `${card.color}20` }}>
                    <Icon className="w-8 h-8" style={{ color: card.color }} />
                  </div>
                  <h3 className="text-center font-semibold text-gray-800 text-sm sm:text-base relative z-10">{card.title}</h3>
                </div>
              </div>
            );
          })}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-white rounded-3xl p-6 shadow-xl shadow-teal-900/20 border border-white/20">
            <div className="flex items-center gap-2 mb-4 pb-4 border-b border-gray-100">
              <div className="p-2 bg-blue-50 rounded-lg text-blue-600"><Calendar className="w-5 h-5" /></div>
              <h3 className="font-bold text-gray-800">Next Appointment</h3>
            </div>
            {appointments.length > 0 ? (
              <div className="space-y-3">
                {conditions.length > 0 ? (
                  <div>
                    <label className="text-xs text-gray-400 uppercase font-bold tracking-wider block mb-2">Current Conditions</label>
                    <div className="flex flex-wrap gap-2">
                      {conditions.slice(0, 3).map((condition, idx) => (
                        <span key={idx} className="px-3 py-1 bg-red-50 text-red-600 rounded-lg text-xs font-medium border border-red-100">{condition}</span>
                      ))}
                    </div>
                  </div>
                ) : (
                  <p className="text-gray-500 text-sm">No conditions recorded</p>
                )}
                {medications.length > 0 && (
                  <div>
                    <label className="text-xs text-gray-400 uppercase font-bold tracking-wider block mb-2">Active Medications</label>
                    <p className="text-sm font-semibold text-gray-700">{medications.length} medication(s)</p>
                  </div>
                )}
              </div>
            ) : (
              <p className="text-gray-500 text-center py-6">No appointments scheduled</p>
            )}
          </div>

          <div className="bg-white rounded-3xl p-6 shadow-xl shadow-teal-900/20 border border-white/20">
            <div className="flex items-center gap-2 mb-4 pb-4 border-b border-gray-100">
              <div className="p-2 bg-green-50 rounded-lg text-green-600"><Activity className="w-5 h-5" /></div>
              <h3 className="font-bold text-gray-800">Health Overview</h3>
            </div>
            <div className="space-y-3">
              {userData.currentMedical?.conditions && userData.currentMedical.conditions.length > 0 ? (
                <div>
                  <label className="text-xs text-gray-400 uppercase font-bold tracking-wider block mb-2">Current Conditions</label>
                  <div className="flex flex-wrap gap-2">
                    {userData.currentMedical.conditions.slice(0, 3).map((condition, idx) => (
                      <span key={idx} className="px-3 py-1 bg-red-50 text-red-600 rounded-lg text-xs font-medium border border-red-100">{condition}</span>
                    ))}
                  </div>
                </div>
              ) : (
                <p className="text-gray-500 text-sm">No conditions recorded</p>
              )}
              {userData.currentMedical?.medications && userData.currentMedical.medications.length > 0 ? (
                <div>
                  <label className="text-xs text-gray-400 uppercase font-bold tracking-wider block mb-2">Active Medications</label>
                  <p className="text-sm font-semibold text-gray-700">{userData.currentMedical.medications.length} medication(s)</p>
                </div>
              ) : null}
            </div>
          </div>
        </div>
      </main>

      {activeModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50 backdrop-blur-sm" onClick={() => setActiveModal(null)}>
          <div className="bg-white rounded-3xl shadow-2xl max-w-4xl w-full max-h-[90vh] overflow-y-auto p-6 sm:p-8 relative" onClick={(e) => e.stopPropagation()}>
            <button onClick={() => setActiveModal(null)} className="absolute top-4 right-4 text-gray-400 hover:text-gray-700 p-2 bg-gray-100 rounded-full z-10 transition-colors">
              <X className="w-6 h-6" />
            </button>
            {renderModal()}
          </div>
        </div>
      )}

      {showSummaryModal && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-2xl flex flex-col max-h-[85vh] overflow-hidden border border-white/20">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-white shrink-0">
              <div className="flex items-center gap-3">
                <div className="p-2 bg-purple-100 rounded-lg"><Sparkles className="w-5 h-5 text-purple-600" /></div>
                <h2 className="text-xl font-bold text-gray-800">AI Medical Summary</h2>
              </div>
              <button onClick={() => setShowSummaryModal(false)} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-full text-gray-500 transition-colors">
                <X className="w-5 h-5" />
              </button>
            </div>
            <div className="p-6 overflow-y-auto flex-1 bg-white">
              <div className="mb-6">
                <p className="text-xs font-bold text-gray-400 uppercase tracking-wider mb-3">Analyzed Documents ({recentDocs.length})</p>
                <div className="flex flex-wrap gap-2">
                  {recentDocs.map(doc => (
                    <span key={doc.id} className="px-3 py-1 bg-purple-50 text-purple-700 border border-purple-100 rounded-full text-xs font-semibold">{doc.name}</span>
                  ))}
                </div>
              </div>
              <div className="bg-gray-50 rounded-xl p-6 border border-gray-100">
                <div className="text-gray-700 whitespace-pre-wrap break-words font-sans text-base leading-loose">{summaryText || '🤖 Processing...'}</div>
              </div>
            </div>
            <div className="p-4 border-t border-gray-100 bg-gray-50 shrink-0">
              <button className="w-full flex items-center justify-center gap-2 py-3 rounded-xl bg-purple-600 text-white font-bold hover:bg-purple-700 transition shadow-lg text-sm sm:text-base">
                <FileText className="w-5 h-5" /> Download PDF
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function CalendarView({ appointments, onAddAppointment, onDeleteAppointment }: any) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const monthNames = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

  const getDaysInMonth = (date: Date) => {
    const year = date.getFullYear();
    const month = date.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const days: (Date | null)[] = [];
    for (let i = 0; i < firstDay; i++) days.push(null);
    for (let day = 1; day <= daysInMonth; day++) days.push(new Date(year, month, day));
    while (days.length < 42) days.push(null);
    return days;
  };

  const getAppointmentsForDate = (date: Date) => {
    const key = formatDateKey(date);
    return appointments.filter((apt: any) => apt.date === key);
  };

  const days = getDaysInMonth(currentDate);

  return (
    <div>
      <div className="flex items-center gap-3 mb-6">
        <div className="p-3 bg-blue-100 rounded-xl"><Calendar className="w-8 h-8 text-blue-700" /></div>
        <h2 className="text-2xl font-bold text-gray-800">Calendar</h2>
      </div>

      <div className="flex items-center justify-between mb-4">
        <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} className="p-2 bg-[#006770] text-white rounded-lg hover:bg-[#006770]/80">
          <ChevronLeft className="w-4 h-4" />
        </button>
        <span className="text-lg font-bold text-gray-800">{monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}</span>
        <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-2 bg-[#006770] text-white rounded-lg hover:bg-[#006770]/80">
          <ChevronRight className="w-4 h-4" />
        </button>
      </div>

      <div className="bg-white rounded-2xl p-4 sm:p-6 border border-gray-100 mb-6">
        <div className="grid grid-cols-7 gap-2 text-center mb-4">
          {['Su','Mo','Tu','We','Th','Fr','Sa'].map(d => (<div key={d} className="text-xs sm:text-sm font-bold text-gray-400 uppercase">{d}</div>))}
        </div>
        <div className="grid grid-cols-7 gap-2">
          {days.map((date, idx) => (
            !date ? <div key={idx} className="h-16 sm:h-20"></div> : (
              <div key={idx} className="h-16 sm:h-20 flex flex-col items-center justify-start text-sm rounded-lg p-1 bg-white text-gray-700 border border-gray-100 hover:bg-teal-50">
                <span className="font-semibold text-xs">{date.getDate()}</span>
                {getAppointmentsForDate(date).length > 0 && (
                  <div className="flex flex-col mt-1 w-full gap-1">
                    {getAppointmentsForDate(date).slice(0, 2).map((appt: any) => (
                      <div key={appt.id} className="text-[8px] leading-snug text-left truncate w-full bg-[#006770] text-white rounded px-1 py-px">
                        {appt.title.length > 8 ? `${appt.title.substring(0, 8)}…` : appt.title}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )
          ))}
        </div>
      </div>

      <h3 className="font-bold text-gray-800 mb-3 text-sm uppercase">All Appointments</h3>
      <div className="space-y-3 max-h-[300px] overflow-y-auto">
        {appointments.length === 0 ? (
          <p className="text-gray-500 text-center py-4">No appointments</p>
        ) : (
          appointments.sort((a: any, b: any) => new Date(a.date).getTime() - new Date(b.date).getTime()).map((appt: any) => (
            <div key={appt.id} className="flex items-center gap-4 p-3 bg-white border border-gray-100 rounded-2xl hover:bg-teal-50 shadow-sm">
              <div className="flex flex-col items-center bg-teal-100 text-teal-800 px-3 py-1 rounded-lg min-w-[60px]">
                <span className="text-xs font-bold">{new Date(appt.date).toLocaleDateString('en-US', { month: 'short' })}</span>
                <span className="text-lg font-bold">{new Date(appt.date).getDate()}</span>
              </div>
              <div className="flex-1">
                <p className="font-bold text-gray-800">{appt.title}</p>
                <p className="text-xs text-gray-500">{appt.time}</p>
              </div>
              <ChevronRight className="w-5 h-5 text-gray-300" />
            </div>
          ))
        )}
      </div>
    </div>
  );
}

function EmergencyView({ data, onDelete }: any) {
  return (
    <div>
      <div className="flex items-center gap-3 mb-6"><div className="p-3 bg-red-100 rounded-xl"><Phone className="w-8 h-8 text-red-600" /></div><h2 className="text-2xl font-bold text-gray-800">Emergency Contacts</h2></div>
      <div className="space-y-3">
        {data.length === 0 ? <p className="text-gray-500 text-center py-4">No contacts</p> : data.map((contact: any, idx: number) => (
          <div key={idx} className="p-4 border border-gray-100 rounded-xl bg-white flex items-center justify-between">
            <div className="flex-1"><p className="font-bold text-gray-900">{contact.name}</p><p className="text-sm text-gray-500">{contact.relation} • {contact.phone}</p></div>
            <button onClick={() => onDelete(idx)} className="p-2 bg-red-50 text-red-600 rounded-full hover:bg-red-100"><Trash2 className="w-4 h-4" /></button>
          </div>
        ))}
      </div>
    </div>
  );
}

function DoctorsView({ data }: any) {
  return (
    <div>
      <div className="flex items-center gap-3 mb-6"><div className="p-3 bg-teal-100 rounded-xl"><Stethoscope className="w-8 h-8 text-teal-600" /></div><h2 className="text-2xl font-bold text-gray-800">Medical Team</h2></div>
      <div className="space-y-3">
        {data.length === 0 ? <p className="text-gray-500 text-center py-4">No doctors</p> : data.map((doc: any, idx: number) => (
          <div key={idx} className="p-4 border border-gray-100 rounded-xl bg-white"><p className="font-bold text-gray-900">{doc.name}</p><p className="text-sm text-gray-500">{doc.speciality}</p><p className="text-sm text-blue-600">{doc.phone}</p></div>
        ))}
      </div>
    </div>
  );
}

function MedsView({ data }: any) {
  return (
    <div>
      <div className="flex items-center gap-3 mb-6"><div className="p-3 bg-orange-100 rounded-xl"><Pill className="w-8 h-8 text-orange-600" /></div><h2 className="text-2xl font-bold text-gray-800">Medications</h2></div>
      <div className="space-y-3">
        {data.length === 0 ? <p className="text-gray-500 text-center py-4">No medications</p> : data.map((med: any, idx: number) => (
          <div key={idx} className="p-4 border border-gray-100 rounded-xl bg-white"><div className="grid grid-cols-1 md:grid-cols-3 gap-4"><div><p className="text-sm text-gray-500">Name</p><p className="font-semibold text-gray-900">{med.name}</p></div><div><p className="text-sm text-gray-500">Dosage</p><p className="font-semibold text-gray-900">{med.dosage}</p></div><div><p className="text-sm text-gray-500">Frequency</p><p className="font-semibold text-gray-900">{med.frequency}</p></div></div></div>
        ))}
      </div>
    </div>
  );
}